INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CSW-3SSN-O', '埋込スイッチボックス 3個用(極薄型) 塗代無', '深さ35mmの極薄型! 平塗代カバー付は、ボックスの内側に収まるフラットタイプ。ノックがドライバーで開けられます。ボックスの傾き防止ができる、便利な4mmバー取り付け穴付。軽量間柱への直接取り付けに便利な側面ビス穴ノック付。スタット無。(ø11の穴付)。仕切板なし。', 1280, 'https://dummyimage.com/200x200/cccccc/000.png&text=CSW-3SSN-O', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 182, 83.5, 35);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CSW-3SSNF', '埋込スイッチボックス 3個用(極薄型) 平塗代付', '深さ35mmの極薄型! 平塗代カバー付は、ボックスの内側に収まるフラットタイプ。ノックがドライバーで開けられます。ボックスの傾き防止ができる、便利な4mmバー取り付け穴付。軽量間柱への直接取り付けに便利な側面ビス穴ノック付。スタット無。(ø11の穴付)。仕切板(57M)付。', 1540, 'https://dummyimage.com/200x200/cccccc/000.png&text=CSW-3SSNF', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 182, 83.5, 35);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CDO-K30', '浅型配線カバー', 'かぶり厚30mmのコンクリート打込み箇所のケーブル配線工事に使用します。柱回りでは主筋より内側に入らず施工することができます。ボックス継枠を使用すれば30mm以上の打込み箇所にも使用できます。側面ノックアウト 16(19)×2, 22(25)×2。', 260, 'https://dummyimage.com/200x200/cccccc/000.png&text=CDO-K30', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 141, 118, 23);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CDO-16SG', '埋込スイッチボックス CD管16 1方出(Gタイプ)ハブ付 塗代カバー付', 'コネクタの取り付け不要! おトクなハブ付です。ボックスの傾き防止ができる、便利な4mmバー取り付け穴付です。スタット・塗代カバー付です。Gタイプのハブですから、接続も解除も一発でOKです。2個のハブ付は、送り配管に便利です。側面ノックアウト 22・22(25・25)×2, 22(25)×1。', 540, 'https://dummyimage.com/200x200/cccccc/000.png&text=CDO-16SG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 72, 117, 45);
