INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CD8-75HG', 'CDハブ付八角コンクリートボックス CD管16', 'コネクタの取り付け不要! おトクなハブ付です。ボックス内にコネクタが出ていませんから、広く使えます。蓋はビスを緩めるだけで取り外せます。ハブ(受け口)内側にトロ防止ノック付! 側面ノックアウト 22(25)×4, 上面ノックアウト 16(19)×1。', 720, 'https://dummyimage.com/200x200/cccccc/000.png&text=CD8-75HG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 130, 100, 45);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'OF-17', '自在塗代ボックス', 'タイル貼りの壁へ器具を取り付ける際の目地合わせに使用します。配管後、ボックスにフリーボードを取り付け、4mmバー等で配筋に固定します。ボックス内調整範囲 左右40mm, 上下70mm (5mmピッチ)。', 4020, 'https://dummyimage.com/200x200/cccccc/000.png&text=OF-17', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 134, 194, 59);
