INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'RCDO-K4A', '軽量間仕切り用 両面アウトレットボックス 中形四角(浅型)', '両面使用できます。ボックス両面に平塗代カバーを取り付け、間柱内に収まります。側面固定台座により、軽量間柱に固定できます! W3/8ボルト、調整固定バーを通し、軽量間柱に固定できます。ノックがドライバーで開けられます。壁厚50mm。', 480, 'https://dummyimage.com/200x200/cccccc/000.png&text=RCDO-K4A', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 108, 133, 50);
