INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CDO-4AKGP', '軽量間仕切り用 スライドアウトレットボックス 丸型(丸孔カバー)', '軽量間柱がズレた場合のボックス位置調整が容易にできます。(軽量間仕切り用調整固定バーにセットして使用します。) 丸型(丸孔カバー)。', 320, 'https://dummyimage.com/200x200/cccccc/000.png&text=CDO-4AKGP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 108, 83.5, 60);
