INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBT', 'スライドTLボックス', '電話・TV・インターホン・チャイム等の配管用の端末、中継ボックスに使用します。受け口のツメにより差し込むだけで、ガッチリ接続できます。スリーブ2個付。TLフレキ14を接続する場合は付属のスリーブを使用します。', 640, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 55, 33.4, 36);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBT-2L', '大型スライドTLボックス', 'ブランク部分があるので、配線スペースが広くLANケーブル等の配線も容易です。14・16変換アダプタ2個付。', 830, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBT-2L', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, 102, 44);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBT-12LW', '大型スライドTLボックス (2個用)', 'サイズ22の波付管(CD・PF・TLフレキ)が4本並べて配管できます。変換アダプタ(4組付)によりサイズ14・16の波付管も配管できます。ブランク部分があるので、配線スペースが広くLANケーブル等の配線も容易です。仕切板(53M)付。14・16変換アダプタ4個付。', 1210, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBT-12LW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 134.3, 83.5, 36);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBTV-3HD', 'ユニットボックス28 (センター磁石付)', '壁掛けテレビの配線に最適。HDMI、LAN、同軸等複数のケーブル配線に対応するサイズ28の波付管が最大8本接続できます。壁内空間45mm以上の環境下でご使用いただけます。センター磁石付なので小判穴ホルソーでの穴あけが簡単です。(本製品は3個用仕様)。', 2500, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBTV-3HD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 215, 168, 45);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBTV-22', 'ユニットボックス (情報機器ボックス) 2ヶ用', '整合器取り付けスペースが広く、配線がラクです。2ヶ用。', 1000, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBTV-22', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50.5, 168, 34);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBTV-3W', 'ユニットボックス (情報機器ボックス) 3ヶ用', '整合器取り付けスペースが広く、配線がラクです。3ヶ用には管サイズ14・16を接続できる変換アダプタが付いています。', 1980, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBTV-3W', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 192, 168, 40);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SM40-3WNF', '真壁用スイッチボックス 3個用(浅形)', '薄壁に最適な3個用スイッチボックスです。3分スタット付。仕切板(26MA)付。', 1300, 'https://dummyimage.com/200x200/cccccc/000.png&text=SM40-3WNF', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 182, 122, 40);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBR-BJ', '外かベボックス (ケーブル配線用防雨型露出スイッチボックス) ツバ管付', '防雨コンセント・スイッチ・プレート等の取り付け用防雨型露出スイッチボックスです。防雨パッキンにより、壁内への雨水の浸入を防ぎます。通線孔には付属のツバ管(MT-22J)の他に、塩ビ管(VE16)が適合し、絶縁もバッチリです。ツバ管付。', 760, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBR-BJ', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 76.5, 114, 37);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVU-BKJ', 'ユニバーサルボックス(ブランクタイプ) 1~4方出兼用型 (ベージュ)', '蓋の取り外し、取り付けがビス1本でできます。ボックスと蓋の境目が無いスマートなデザインです。キャップを外し、コネクタを直接取り付けられます。(ロックナット不要)1~4方出兼用でコネクタにより異種管(CD管・PF管・VE管)の接続ができます。ベージュ。', 800, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVU-BKJ', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 100, 100, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVU-BKM', 'ユニバーサルボックス(ブランクタイプ) 1~4方出兼用型 (ミルキーホワイト)', '蓋の取り外し、取り付けがビス1本でできます。ボックスと蓋の境目が無いスマートなデザインです。キャップを外し、コネクタを直接取り付けられます。(ロックナット不要)1~4方出兼用でコネクタにより異種管(CD管・PF管・VE管)の接続ができます。ミルキーホワイト。', 800, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVU-BKM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 100, 100, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVU-BK', 'ユニバーサルボックス(ブランクタイプ) 1~4方出兼用型 (グレー)', '蓋の取り外し、取り付けがビス1本でできます。ボックスと蓋の境目が無いスマートなデザインです。キャップを外し、コネクタを直接取り付けられます。(ロックナット不要)1~4方出兼用でコネクタにより異種管(CD管・PF管・VE管)の接続ができます。グレー。', 800, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVU-BK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 100, 100, 50);
