INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-MA3-CS', '中形四角(浅型) 耐火遮音スタットレットボックス (台座あり)', '防火性能が高い、ボックスと側面固定台座が鉄製の遮音ボックス。側面固定台座により、間柱に簡単に固定できる。鉄製平塗代カバーをご使用ください。側面ノックアウト:22・22(25・25)×3。耐火中空壁に使用する場合、当社タイカスールBP3と組み合わせて使用。', 1820, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-MA3-CS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 128.3, 127, 51);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-MA3CSN', '中形四角(浅型) 耐火遮音スタットレットボックス (台座なし)', '防火性能が高い、ボックスと側面固定台座が鉄製の遮音ボックス。側面固定台座により、間柱に簡単に固定できる。鉄製平塗代カバーをご使用ください。側面ノックアウト:22・22(25・25)×3。取り付けには自在バー、調整固定バー等を使用。耐火中空壁に使用する場合、当社タイカスールBP3と組み合わせて使用。', 1820, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-MA3CSN', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 128.3, 127, 51);
