INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SM36-NXP-1', 'X線防護用スイッチボックス', '鉛当量:2.0mm, 重量:1.0kg, 鉛ボード用 1ヶ用(深さ36mm)。レントゲン室等のX線の遮へいが必要な箇所に使用。あらかじめ鉛板でボックスを覆ってある組み付け品ですから、鉛板に隙間がなく、X線の遮へいに最適です。鉛を加工する手間がいらず、施工が簡単!折り取り磁石が取り付けられます。鉛表面に保護シールが貼ってあるので安全に取り扱うことができます。', 12000, 'https://dummyimage.com/200x200/cccccc/000.png&text=SM36-NXP-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, 36);
