INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'OF-3NFXP4-1', 'X線防護用埋込スイッチボックス(鉄製セーリスボックス)', '鉛当量:2.0mm, 重量:2.3kg, 鉛ボード用・4方出, 電着塗装(色:黒), 平塗代カバー付, 3個用, ノックアウト: 22-22-22(25-25-25)×2, 22-22(25-25)×2。軽量間柱にボックス支持部材を取り付け、ボックス底面のスタットバー固定穴よりX線防護用スイッチボックスをねじ止め固定します。X線防護用ボックスジョイント×1個付, 補助鉛テープ×2枚付。', 16000, 'https://dummyimage.com/200x200/cccccc/000.png&text=OF-3NFXP4-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 234.5, 184.5, 83.5);
