INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XPL-RW34', 'X線防護用 照明器具カバー (露出照明取付ボルト用)', '鉛当量:2.0mm, 適合ボルト: W3/8, W1/2, M10, M12, 下穴径: φ30以下。レントゲン室等のX線の遮へいが必要な部屋で、二重天井に吊りボルトを貫通させて照明器具を取り付ける際に、ボルト貫通部の保護カバーとして使用。吊りボルトに押し込むだけでセットでき、後から二重天井を貼る際に一緒に押し込まれていく構造になっているので隙間ができません。ナットのように回していくだけでボルトからの解除も簡単。手で触れる鉛表面が樹脂で覆われている為、安全に施工できます。', 1480, 'https://dummyimage.com/200x200/cccccc/000.png&text=XPL-RW34', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 59, 51, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'XPL-DL100', 'X線防護用 照明器具カバー (ダウンライト・非常灯用)', '鉛当量:2.0mm, 重量:4.3kg, 適用機器: SB形ダウンライト, SB形非常灯, 適用開口径: ばね式(φ100迄), はさみ金具(φ150迄)。レントゲン室等のX線の遮へいが必要な部屋で、二重天井にダウンライトや非常灯を設置する場合の開口部の防護に使用。天井を貼る前に設置しておくだけで、設置後は従来の電気工事と同じように施工できます。鉛部分には保護シートが貼ってある為、安心して施工できます。野縁(野縁受け)への固定金具での固定の他に、吊りボルトでの取り付けや木製野縁へのビス固定も可能。X線防護用ボックスジョイント×1個付, 固定金具(M6)×2個付, ロックナット×1個付, 補助鉛テープ×2枚付。', 38400, 'https://dummyimage.com/200x200/cccccc/000.png&text=XPL-DL100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 354, 99, 204);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'C2A0-T', 'アースターミナルボックス (透明蓋(屋根無))', 'IV線: 5.5mm²×10。病院、診療所における感電防止対策に用いる、医療設備用接地センタ付。吊りボルトに取り付け可能なボルトクリップ付。ボルトクリップ2個付。', 17400, 'https://dummyimage.com/200x200/cccccc/000.png&text=C2A0-T', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 195, 274, 130);
