INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NBS-3X', 'ポイントアッター® (ボックス発見用磁石)', '適合ホルソー:SBホルソー(φ77)。塗代カバーに取り付け、ボックスの探知に使用。探知距離アップの厚壁対応タイプもあり。マグネットアッター(BUT-SP3)を使用すると探知距離50mm迄探知。(NBS-3Aは除く)', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=NBS-3X', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 60, NULL);
