INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NBS-3C', 'ポイントアッター® (バネ爪タイプ) (ボックス発見用磁石)', '適合ホルソー:小判穴ホルソー。塗代カバーに取り付け、ボックスの探知に使用。取付部がばね爪なので、鉄製塗代カバーに最適。マグネットアッター(BUT-SP3)を使用すると探知距離50mm迄探知できます。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=NBS-3C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 83.5, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NBS-3C60', '超ポイントアッター (バネ爪タイプ) (探知距離アップ用強力磁石)', '適合ホルソー:小判穴ホルソー。塗代カバーに取り付け、ボックスの探知に使用。厚壁対応、探知距離アップの強力磁石です。(~60mm迄)取付部がばね爪なので、鉄製塗代カバーに最適です。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=NBS-3C60', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 83.5, NULL);
