INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GLK-16SF2', 'ミラグランド® (ボックス用)', '色:ベージュ。適合:VVF1.6×2C・VVF2.0×2C, 適合ノック径:φ21~φ22, 電線管の呼び:16, ねじの呼び:G1/2。ケーブルを乾式で固定・防水処理ができるボックス用ケーブルグランド。袋ナットを締めることで内部の防水ゴムを圧縮し、幅広いケーブル径に対応。屋外でも使用。IP67。', 350, 'https://dummyimage.com/200x200/cccccc/000.png&text=GLK-16SF2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, NULL, 50.5);
