INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'OF-5004', '4mmバー (傾き防止バー) (回転ストッパー付)', '規格:φ4×500mm, ビス(4個)で1組。適合ボックス:当社プラスチック製ボックス(埋込四角アウトレットボックス)。当社プラスチック製ボックス(埋込四角アウトレットボックス、埋込スイッチボックス)の傾き防止に便利なバー(4mm鉄線)。壁面、スラブの配筋を利用し、ボックスが簡単に取り付けられ、傾き防止。自在に曲げられる4mm鉄線。回転ストッパー付はボックスへ差し込むだけでOK!', 140, 'https://dummyimage.com/200x200/cccccc/000.png&text=OF-5004', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 4, 500, NULL);
