INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-4BT', 'バインドハンガー® (粘着テープタイプ)', '制御盤内部や軽量間柱内でのケーブルの整頓等に最適なケーブル用ハンガーです。二重天井を吊る前の先行配線等にも使用できます。SCH-5BTCは入数が多い安価なエコノミータイプです。', 170, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-4BT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 43, 30);
