INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-B4', 'バインドハンガー® (丸バインドタイプ)接着タイプ', '天井面や壁面への先行配線等に使用するケーブル用ハンガーです。接着剤固定タイプですから施工場所を選びません。丸バインドタイプなのでケーブルがシッカリ固定できます。製品同士を連結できますので配線が集中する箇所で配線を整列できます。間柱など壁面への固定もできるようビス穴が設けてあります。', 52, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-B4', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 40, NULL);
