INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVH-10', 'ケーブルホルダー10 (接着タイプ)', '二重天井を吊る前のVVFケーブルの先行配線(支持)等に使用する、ケーブル支持具です。接着剤固定タイプですから施工場所を選びません。(壁面にも使用できます。)カバーが一体成形されていますのでケーブルが落下する恐れがありません。カラーインサート(NK-3)にもビス固定できます。VVFケーブル(10本迄)対応。', 360, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVH-10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, 13, 105);
