INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGSCH-1BE', 'ケーブルハンガー(結束バンド付)(鋲打機用)', '天井面、壁面へのケーブルの取り付け(支持)に使用します。鋲打機固定タイプですのでスピーディーに施工ができます。結束バンド付なので、ケーブルをシッカリ固定できます。(結束バンドは解除可能です。)', 120, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGSCH-1BE', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 26.5, 38.5, 85.9);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGSCH-1', 'ケーブルハンガー(鋲打機用)', '壁面、天井面へのケーブルの取り付け(支持)に使用します。鋲打機固定タイプですのでスピーディーに施工ができます。壁面使用時では内蔵ハンガーを使って二段にケーブル配線できます。軽天ビス等での固定もできます。適合結束バンド幅:6mm以下。', 190, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGSCH-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 41, 80, 35);
