INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ACH-1T', 'ケーブルハンガー(タッカー対応タイプ)', '固定する際ハンガー部が邪魔にならない構造なので施工が容易です。当社ケーブルタッカーでも固定できます。ケーブル等が挿入しやすく抜けにくい構造です。', 68, 'https://dummyimage.com/200x200/cccccc/000.png&text=ACH-1T', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 29.5, 64, 22);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ACH-C3Z', 'ケーブルハンガー (ALC・木材用)ビス釘付', 'ALC・木材へのVVFケーブル取り付け(支持)に使用します。取り付けは簡単! 釘を打ち込むだけです。ケーブル等の垂れが気になる場合や増線が必要な場合に結束バンドによる固定ができます。製品同士をタテに整列できます。', 93, 'https://dummyimage.com/200x200/cccccc/000.png&text=ACH-C3Z', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 18, 80, 17.7);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-CB10', 'バインドハンガー®(10連タイプ) 軽天ビス付', '木間仕切り等への先行配線等に使用するケーブル用ハンガーです。10連タイプでバインド線の絡まりがありませんから、作業がスピーディーに行えます。軽天ビス付は、軽量間仕切り・木間仕切りどちらにも使用できます。', 430, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-CB10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 31, 138, 31);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-CK10', 'バインドハンガー®(10連タイプ) 釘付', '木間仕切り等への先行配線等に使用するケーブル用ハンガーです。10連タイプでバインド線の絡まりがありませんから、作業がスピーディーに行えます。', 430, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-CK10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 31, 138, 31);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-CB10N', 'バインドハンガー®(10連タイプ) ビス無', '木間仕切り等への先行配線等に使用するケーブル用ハンガーです。10連タイプでバインド線の絡まりがありませんから、作業がスピーディーに行えます。', 430, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-CB10N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 31, 138, 31);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-CK10V', 'バインドハンガー®(タテ10連タイプ)', '木柱等を使用した壁面への先行配線等に使用するケーブル用ハンガーです。上から順に釘固定後、ちぎって使う連続作業に最適な10連タイプです。バインド線の絡まりもなく作業がスピーディーに行えます。', 430, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-CK10V', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 31, 315.5, 31);
