INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-10', 'バインドハンガー®(デッキプレート用)', 'デッキプレートへのケーブルの取り付け(支持)に使用します。デッキプレートへの下穴が小さく施工が簡単です。(φ5が最適です。)粘着テープ付は、下階へのト口漏れも防止できます。バインド線長さ: 200mm。適用: デッキプレート厚(0.8mm~1.6mm), 下穴ドリル径(φ5)。', 58, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 25, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-10T', 'バインドハンガー®(デッキプレート用)', 'デッキプレートへのケーブルの取り付け(支持)に使用します。デッキプレートへの下穴が小さく施工が簡単です。(φ5が最適です。)粘着テープ付は、下階へのト口漏れも防止できます。バインド線長さ: 200mm。適用: デッキプレート厚(0.8mm~1.6mm), 下穴ドリル径(φ5)。', 82, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-10T', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 25, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-10S', 'バインドハンガー®(デッキプレート用) パッキン付', 'デッキプレートへのケーブルの取り付け(支持)に使用します。下穴にはめ込むだけの簡単取り付けです。パッキン付ですので下穴からの水漏れが軽減できます。バインド線長さ: 210mm。適用: デッキプレート厚(0.8mm~1.6mm), 下穴ドリル径(φ10)。', 68, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-10S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 20, NULL, NULL);
