INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-5G', 'マグネットハンガー', '二重天井を吊る前の先行配線に使用するケーブル用ハンガーです。平らな金属面に磁石でピッタリ取り付けられますから、即配線工事が可能です。弊社吊りバンドによりケーブル等が吊り下げられます。強力磁石付。適合吊りバンド: MDB-20, MDBP-15-MDBP-25。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-5G', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 22.2, 11.7, 54);
