INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CLT-9E', 'クランプチューブ (ナチュラル)', '束線の湾曲部、扉への渡線、盤間渡線の保護、ロボット等のシリンダー伸縮部、分岐の多い配線束、配線の整理等に使用。巻きつける手間がなく、作業時間を短縮。取りはずしができ、繰り返して使用可能。スリットを施してあるので、曲線部分でも柔軟に装着可能。専用工具付。ポリエチレン製。束線径(d):9mm。肉厚(P):0.8mm。長さ(m/把):100m。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=CLT-9E', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 10.6, NULL, NULL);
