INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SB22', '配管スライドボックス 深さ40mm 1ヶ用', '波付管(16・22)が並列配管できます。(CD単層波付管(22)が1ヶ用で2本、2ヶ用で4本、3ヶ用で5本、並列配管できます。)ボックスの横から差し込める横はめノックですから、背面が壁でもOK! 薄壁での施工にもラクラク対応します。磁石を取り付ければボックス穴をホルソーで簡単にあけられます。アルミ箔付、ホルソー穴あけ対応品、タッピンねじ付。', 200, 'https://dummyimage.com/200x200/cccccc/000.png&text=SB22', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 61, 52, 40);
