INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBTV-3HD', 'ユニットボックス28 (センター磁石付)', '壁掛けテレビの配線に最適。HDMI、LAN、同軸等複数のケーブル配線に対応するサイズ28の波付管が最大8本接続できます。壁内空間45㎜以上の環境下でご使用いただけます。センター磁石付なので小判穴ホルソーでの穴あけが簡単です。(本製品は3個用仕様)。アルミ箔付、磁石付。', 2500, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBTV-3HD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 168, 83.5, 45);
