INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-2F', 'パネルボックス (鉄製) (2ヶ用)', '間仕切り壁等、木ねじの効かないせっこうボード、木板へのスイッチボックスあと付けに最適です。スライドツメがガッチリボックスを固定します。取り付け簡単、作業時間が短縮できます。底面全面をカットアウト! 広い面積で抜くことができます。(丸穴ノックアウトも単独で抜けます。) 壁厚(取付ボード厚) 7~29mm迄。開口寸法(角穴) 99×99mm。', 1400, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-2F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 106, 98.5, 38.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-2FM', 'パネルボックス (鉄製) (2ヶ用)(仕切板付)', '間仕切り壁等、木ねじの効かないせっこうボード、木板へのスイッチボックスあと付けに最適です。スライドツメがガッチリボックスを固定します。取り付け簡単、作業時間が短縮できます。底面全面をカットアウト! 広い面積で抜くことができます。(丸穴ノックアウトも単独で抜けます。) 壁厚(取付ボード厚) 7~29mm迄。仕切板(56M)付。開口寸法(角穴) 99×99mm。', 1430, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-2FM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 106, 98.5, 38.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-KL', 'パネルボックス (感知器用) (カベ白)', '感知器取り付け用のパネルボックスです。SBP-Kは商用電源を使用しない感知器、天井スピーカーの配線ボックスに便利です。塵、ほこり、ねずみの糞尿等による感知器の誤動作を防止します。SBP-KLは丸形プレートが取り付きます。取付ボード厚 (3~25mm迄)。取付孔 (ホルソー径) φ77~φ80。感知器フランジ外径 φ100~φ104。感知器取付ピッチ 66.7mm。適合丸形プレート φ105。', 450, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-KL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 102, 102, 33.7);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-K', 'パネルボックス (感知器用) (弱電用)', '感知器取り付け用のパネルボックスです。SBP-Kは商用電源を使用しない感知器、天井スピーカーの配線ボックスに便利です。塵、ほこり、ねずみの糞尿等による感知器の誤動作を防止します。取付ボード厚 (3~18mm迄)。取付孔 (ホルソー径) φ63.5(2 1/2in)。感知器フランジ外径 φ92~φ104。感知器取付ピッチ 66.7mm。', 380, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 102, 102, 28);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-N', 'パネルボックス', 'デンコーホルソーで丸穴をあけ、取り付けられます。裏ノックを抜けば、CD管・PF管(サイズ14・16)の挿入もできます。壁厚2~30mm迄OK! 最少必要な壁裏空間 46mm。', 450, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 83.5, 108, 51);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBF-0', 'フランジボックス (色:アイボリー) (1ヶ用)', '壁材を張った後や、増設したい時にもあとから埋込めます。小判穴ホルソー、SBホルソーで穴をあけるだけで、壁に即、取り付けられます。(SBホルソーは若干の加工が必要です。) 絶縁枠は取り付きません。', 260, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBF-0', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 73.5, 120, 45.7);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBPT-2', 'はさみ点検口 (2ヶ用)', 'ブランクタイプの化粧プレートを取り付け、壁の点検口として使用します。スライドツメでガッチリ固定します。住宅性能評価対象品。貫通穴径(mm) タテ100×ヨコ100。', 1050, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBPT-2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 97, 108, 35);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBPT-3', 'はさみ点検口 (3ヶ用)', 'ブランクタイプの化粧プレートを取り付け、壁の点検口として使用します。スライドツメでガッチリ固定します。住宅性能評価対象品。貫通穴径(mm) タテ100×ヨコ145。', 1670, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBPT-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 143, 154, 35);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBG-1F-K', '鋼製カバー付スライドボックス (省令準耐火対応キット) (センター磁石付) (浅形(深さ30mm)) (1ヶ用)', '省令準耐火構造の住宅に対応したスイッチボックスと耐火ブッシングがセットになったキット品です。鋼製カバーのボックス取り付け穴が最初から不燃材で養生されています。ボックス穴を小判穴ホルソーであけるセンター磁石付です。耐火ブッシングは、熱膨張材なので、300℃以上の熱を受けると2倍以上に膨らみ火災時の延焼を防止します。', 500, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBG-1F-K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 73, 83, 30);
