INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BZ-1', '気密パッキン (1ヶ用スイッチボックス)', '気密性抜群 浅形・深形兼用。寒冷地等の気密性を要する建物に最適です。本体は蛇腹になっている伸縮自在タイプですから、浅形・深形に兼用できます。適合電線: φ1.6・φ2.0。', 650, 'https://dummyimage.com/200x200/cccccc/000.png&text=BZ-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 70, 120, 42);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLC-2512SA', '気密カバー(ダウンライト用) (粘着テープ付)', '気密性を要する二重天井へのSB形ダウンライト取り付けに使用します。先行取り付けなので、天井板施工後従来同様の工事ができます。適用開口径 φ125迄。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLC-2512SA', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 480, 480, 160);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLC-2512SA-N', '気密カバー(ダウンライト用) (粘着テープ無)', '気密性を要する二重天井へのSB形ダウンライト取り付けに使用します。先行取り付けなので、天井板施工後従来同様の工事ができます。適用開口径 φ125迄。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLC-2512SA-N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 480, 480, 160);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SB-1FA', '気密カバー(吹付断熱材侵入防止タイプ) (1ヶ用)', 'スライドボックス内への吹付断熱材侵入を防ぐ場合に使用する気密カバーです。養生テープを貼り付ける手間がいらず省施工。スライドボックスのタッピンねじで、柱に簡単に取り付けられます。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=SB-1FA', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 90, 276, 39);
