INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SM36-NDK', '結露防止ボックス (真壁用スイッチボックス) (1ヶ用(36mm))', '水分を吸収し、更に吸収した水分を蒸発させる特殊塗料がボックスに塗布してある為、断熱力バーがいりません。結露防止、遮熱に優れています。ボックスの内側に吸水発散成分と防水熱反射成分からなる特殊塗料を塗布することにより結露をゼロにすることに成功しました。特殊塗料にホルムアルデヒド等の揮発性化合物は含まれていません。特殊塗料は不燃性です。施工性は従来のボックスと全く同じ。特殊塗料はボックス内側に塗布してあり、外側は従来通りなので付属品等がそのまま取り付けられます。また、今まで断熱材等の厚みによる空間が必要でしたが、その空間はゼロで済むようになりました。ボックスはJIS規格品に特殊塗料が塗布してあります。(カバーはJIS規格品です。)アルミ箔付。深さ36mm。', 720, 'https://dummyimage.com/200x200/cccccc/000.png&text=SM36-NDK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SM36L-NDK', '結露防止ボックス (真壁用スイッチボックス) (2ヶ用(36mm))', '水分を吸収し、更に吸収した水分を蒸発させる特殊塗料がボックスに塗布してある為、断熱力バーがいりません。結露防止、遮熱に優れています。ボックスの内側に吸水発散成分と防水熱反射成分からなる特殊塗料を塗布することにより結露をゼロにすることに成功しました。特殊塗料にホルムアルデヒド等の揮発性化合物は含まれていません。特殊塗料は不燃性です。施工性は従来のボックスと全く同じ。特殊塗料はボックス内側に塗布してあり、外側は従来通りなので付属品等がそのまま取り付けられます。また、今まで断熱材等の厚みによる空間が必要でしたが、その空間はゼロで済むようになりました。ボックスはJIS規格品に特殊塗料が塗布してあります。(カバーはJIS規格品です。)アルミ箔付。深さ36mm。', 1480, 'https://dummyimage.com/200x200/cccccc/000.png&text=SM36L-NDK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
