INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SB-D8KMA', 'SB台座', 'スライドボックスを軽量間柱に取り付ける場合の台座として使用します。(開口部側へは固定できません。) 「折り取り押さえツバ付」。適合ボックス: SBE, SBE-M, SBE-O, SBE-T, SBE-W(WM), SBO, SBH, SBW, SBW-M, SBH-G, SBS, SBS-W(WM), SBM, SBM-W(WM), SB22, SB22-2。', 140, 'https://dummyimage.com/200x200/cccccc/000.png&text=SB-D8KMA', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 28, 45, 8.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SB-TD23', 'SB高台座', 'スライドボックスを柱から離して取り付けられます。台座は3個迄、連結して使用できます。(1個23mm・2個連結46mm・3個連結69mm)。スライドボックスのねじ溝を台座にはめ込むだけで取り付けられます。適合ボックス: SBE, SBE-M, SBE-O, SBE-W(WM), SBO, SBH, SBW, SBW-M, SBM, SBM-W(WM), SBS, SBS-W(WM), SB22, SB22-2。', 130, 'https://dummyimage.com/200x200/cccccc/000.png&text=SB-TD23', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 28, 23, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBG-TD23', 'SB高台座', 'スライドボックスを柱から離して取り付けられます。台座は3個迄、連結して使用できます。(1個23mm・2個連結46mm・3個連結69mm)。スライドボックスのねじ溝を台座にはめ込むだけで取り付けられます。適合ボックス: SBG, SBG-W(WM), SBG-O, SBG-WO(WOM), SBG-S, SBG-SW(SWM), SBG-SO, SBG-SWO(SWOM), SBG-Y, SBG-YW(YWM)。', 140, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBG-TD23', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 28, 23, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SB-RD', '連結台座 (1ヶ用スライドボックス用)', 'ボックスが背合わせできない薄壁内で、スライドボックスを壁内で正面と背面の交互に連結する場合に使用します。スライドボックスのねじ溝に差し込むだけで取り付けられます。有効壁裏空間 38~50mm。適合ボックス: 用スライドボックス(深さ36mm), SBO, SBH, SBH-G, SB22。', 130, 'https://dummyimage.com/200x200/cccccc/000.png&text=SB-RD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NBS-HD', 'アッターホルダー', 'スライドボックスへの磁石の取り付け、取り外し作業が簡単に行える工具です。適合: ポイントアッター(エコノミータイプ) (品番: NBS-30), スーパーポイントアッター(品番:NBS-40), 超ポイントアッター(品番: NBS-60), スライドアッター(品番: NBS-6), 磁石付きスライドボックス(品番:SBG、SBE等), 磁石付きスライドボックス等の再利用磁石。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=NBS-HD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 100, NULL);
