INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NBS-F', 'アッターF (ケーブル発見用磁石)', 'ケーブルに取り付け、壁施工後のケーブル端末探知に使用します。適合ケーブル: VVFケーブル(1.6×2Cから2.0×3C)。', 76, 'https://dummyimage.com/200x200/cccccc/000.png&text=NBS-F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'HP-1', '枠ちん (1ヶ用)', 'あと付けボックスレス工法に最適なはさみ樹脂枠です。角穴はもちろん、小判穴ホルソー開口穴にも取り付けられるリバーシブル構造です。壁穴空間15mmでも取り付け可能。(角穴取付は20mm)。器具をシッカリ固定! コンセントの取付も安心です。気密カバー(インナータイプ)にも取り付けられます。適合する壁: せっこうボード・合板。', 89, 'https://dummyimage.com/200x200/cccccc/000.png&text=HP-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 65, 75, 49);
