INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PWX-21', 'はさみプラ枠 (ワイド21スイッチ用)', 'はさみ金具と金枠をドッキング! プラスチック製で絶縁性も抜群です。スライドツメが取付枠をガッチリ固定。小判穴ホルソーで小判穴をあけるだけで取り付けられます。枠の連結ができます。最少必要な壁裏空間: 38.5mm以上。取付ボード厚: 4~31mm迄。取付穴寸法: 小判穴(1個用) または 94×47mm(タテ×ヨコ)。', 220, 'https://dummyimage.com/200x200/cccccc/000.png&text=PWX-21', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 45.5, 110, 20);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PWX-1', 'はさみプラ枠 (薄壁に最適)', 'はさみ金具と金枠をドッキング! プラスチック製で絶縁性も抜群です。PWX-1・2はボックスが取り付けない薄壁に最適です。スライドツメが取付枠をガッチリ固定。枠の連結ができます。小判穴ホルソーで小判穴をあけるだけで取り付けられます。最少必要な壁裏空間: 29mm以上。取付ボード厚: 4~22mm迄。取付穴寸法: 小判穴(1個用) または Φ60×2(37mmピッチ)。', 180, 'https://dummyimage.com/200x200/cccccc/000.png&text=PWX-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 47.3, 110, 25);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PWX-1L', 'はさみプラ枠 (薄壁に最適)', 'はさみ金具と金枠をドッキング! プラスチック製で絶縁性も抜群です。PWX-1・2はボックスが取り付けない薄壁に最適です。スライドツメが取付枠をガッチリ固定。枠の連結ができます。小判穴ホルソーで小判穴をあけるだけで取り付けられます。最少必要な壁裏空間: 40mm以上。取付ボード厚: 4~31mm迄。取付穴寸法: 小判穴(1個用) または 94×47mm(タテ×ヨコ)。', 220, 'https://dummyimage.com/200x200/cccccc/000.png&text=PWX-1L', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 47.3, 110, 40);
