INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WK-1', '防水引込みカバー', 'UR都市機構仕様(EF-106-11-B)。外壁から壁内にケーブル等を引き込む際に使用します。(特に給湯暖房機のコントロール線引込みに最適です。)防水パッキン付で防雨性に優れています。カバーが取り外せますから、通線が非常にラクです。ゴムブッシュ付。色：ベージュ', 830, 'https://dummyimage.com/200x200/cccccc/000.png&text=WK-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 74.5, 120, 54.5);
