INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'OPS6', 'ワゴンモール® (ソフトタイプ)', '屋内外兼用。色: 黒、ベージュ、黄。道路上、展示会場通路等の仮設ケーブルの保護に最適。台車、自動車等の車輪が乗り越えやすい緩やかなデザイン。中央の電線通線孔は、入線用スリット入りで入線も容易。屋外の熱や寒さにも強い耐候性のある軟質樹脂製。ソフトタイプ。床面の凹凸、ゆるい曲がり箇所にも対応。ケーブルへの衝撃も吸収。長尺。カッター等でカット可能。', 14500, 'https://dummyimage.com/200x200/cccccc/000.png&text=OPS6', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 58, 15.5, NULL);
