INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CML-1B', 'Cモール® コーナー(隅角)用', '全長:1m。色: 茶。床、壁面コーナー(隅角)への屋内配線の施工に最適。コーナーにジャストフィット。ホコリも溜まらない。床・壁面にマッチする4色展開。基台にはセンター表示の溝あり。VVF 1.6×3C-1条、2.6×2C-1条、LANケーブル、同軸ケーブルに適合。', 450, 'https://dummyimage.com/200x200/cccccc/000.png&text=CML-1B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 15.5, 15.5, NULL);
