INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVMC-DF1609K', 'カメラ取付デザイン丸ボックス', 'ドーム型防犯カメラや取付台座が丸い防犯カメラの取り付けに最適です。オシャレな新型デザイン! 建物の雰囲気や美観を損ないません。蓋が脱着式になっていますので、蓋を取り外してカメラを取り付けられます。屋外での使用に便利な防雨型。ポールにも取り付けられるバンド通し穴付。盗難やいたずら防止用のセキュリティねじもあります。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVMC-DF1609K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 160, 99.2, 74.4);
